#!/usr/bin/env bash
# ghost-relay.sh — a regenerative RF delay-line ("ghost in the machine").
#
# A single datum (a seq counter) is sustained ONLY by continuous regeneration
# through an air hop: Pluto TX → air → RTL RX → decode → increment → re-TX.
# This is the hardware witness for the Lean invariant
# `Gnosis/WireDelayLineGhost.lean` (persistence == circulation):
#
#   * The live value lives in the in-flight frame + a transient regeneration
#     buffer (the $seq shell var) — NEVER written to durable storage (no fsync).
#   * Kill this script, or block the air for > one hop, and the value is gone:
#     the counter stops climbing and does NOT resume at N+1.
#
# HONEST framing (proved, not overclaimed): the value IS recoverable from live
# machine buffers while circulating; only its PERSISTENCE is air-gated. It is a
# recirculating BUFFER store, not free-space storage.
#
# Usage:
#   ghost-relay.sh [hops]            # run <hops> regeneration cycles (default 8)
# Env: GNOSIS_PLUTO_URI (auto-discovered), TX_LO_HZ, SAMPLE_RATE, TX_GAIN_DB.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
GNOSIS_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
HOPS="${1:-8}"

LIBIIO_BUILD="${GNOSIS_LIBIIO_BUILD:-/tmp/libiio_build/build}"
export DYLD_FALLBACK_FRAMEWORK_PATH="${LIBIIO_BUILD}${DYLD_FALLBACK_FRAMEWORK_PATH:+:${DYLD_FALLBACK_FRAMEWORK_PATH}}"
IIO_INFO="${LIBIIO_BUILD}/tests/iio_info"
IIO_ATTR="${LIBIIO_BUILD}/tests/iio_attr"
IIO_WRITEDEV="${LIBIIO_BUILD}/tests/iio_writedev"
CLI=("node" "${GNOSIS_ROOT}/bin/rtlsdr-mock-sim.js")
rtl_bin(){ command -v "$1" 2>/dev/null || { [[ -x "/opt/homebrew/bin/$1" ]] && echo "/opt/homebrew/bin/$1"; } || echo "$1"; }

TX_LO_HZ="${TX_LO_HZ:-433920000}"
SAMPLE_RATE="${SAMPLE_RATE:-2400000}"
TX_GAIN_DB="${TX_GAIN_DB:--10}"
RX_DEVICE="${RX_DEVICE:-0}"
RX_TUNER_GAIN="${RX_TUNER_GAIN:-30}"
HOP_CAPTURE_S="${HOP_CAPTURE_S:-2}"
ART="${GNOSIS_ROOT}/.qa-artifacts/rtlsdr"
mkdir -p "$ART"
IQ="${ART}/ghost.iq16"
CAP="${ART}/ghost-capture.u8"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; YELLOW=$'\033[1;33m'; BLUE=$'\033[0;34m'; NC=$'\033[0m'
log(){ echo "${BLUE}[ghost]${NC} $*"; }

# --- discover Pluto URI ---
PLUTO_URI="${GNOSIS_PLUTO_URI:-}"
if [[ -z "$PLUTO_URI" && -x "$IIO_INFO" ]]; then
  PLUTO_URI="$("$IIO_INFO" -s 2>/dev/null | grep -iE 'pluto|adalm|0456:b673' | grep -oE 'usb:[0-9]+\.[0-9]+\.[0-9]+' | head -1 || true)"
fi
[[ -n "$PLUTO_URI" ]] || { echo "${RED}[ghost] no Pluto transmitter (URI). Cannot circulate.${NC}" >&2; exit 1; }
log "Pluto TX @ ${PLUTO_URI}, RX RTL#${RX_DEVICE}, ${TX_LO_HZ} Hz, ${SAMPLE_RATE} S/s"

# --- TX chain config (hardwaregain write throws EMULTIHOP over USB but takes) ---
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy altvoltage1 frequency "$TX_LO_HZ" >/dev/null 2>&1 || true
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 sampling_frequency "$SAMPLE_RATE" >/dev/null 2>&1 || true
"$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 rf_bandwidth "$SAMPLE_RATE" >/dev/null 2>&1 || true
for _ in 1 2 3; do "$IIO_ATTR" -u "$PLUTO_URI" -c ad9361-phy voltage0 hardwaregain "$TX_GAIN_DB" >/dev/null 2>&1 || true; done

TXPID=""
radiate(){ # $1 = payload — encode to IQ, (re)start cyclic TX
  local payload="$1" frames
  frames="$( { "${CLI[@]}" mars-tx --payload "$payload" --tx-lo-hz "$TX_LO_HZ" --iq-int16-out "$IQ" 2>/dev/null || true; } \
    | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{try{process.stdout.write(String(JSON.parse(s).frameSamples))}catch{process.stdout.write("0")}})' 2>/dev/null || true)"
  [[ "${frames:-0}" -gt 0 ]] || { echo "${RED}[ghost] mars-tx failed${NC}" >&2; return 1; }
  [[ -n "$TXPID" ]] && { kill "$TXPID" 2>/dev/null || true; wait "$TXPID" 2>/dev/null || true; }
  "$IIO_WRITEDEV" -u "$PLUTO_URI" -b "$frames" -c cf-ad9361-dds-core-lpc voltage0 voltage1 < "$IQ" >/tmp/ghost-tx.log 2>&1 &
  TXPID=$!
}
cleanup(){ [[ -n "$TXPID" ]] && { kill "$TXPID" 2>/dev/null || true; wait "$TXPID" 2>/dev/null || true; }; }
trap cleanup EXIT

# --- SEED P0 (the only time a value enters the loop from outside) ---
seq=0
radiate "GHOST/1 seq=${seq}"
log "seed P0: seq=${seq} radiating (in flight). No durable copy written."

decode_seq(){ # capture one window, decode, echo recovered seq or empty
  timeout $((HOP_CAPTURE_S + 8)) "$(rtl_bin rtl_sdr)" -d "$RX_DEVICE" -f "$TX_LO_HZ" -s "$SAMPLE_RATE" \
    -g "$RX_TUNER_GAIN" -n $((SAMPLE_RATE * HOP_CAPTURE_S)) "$CAP" >/dev/null 2>&1 || true
  local out
  out="$( { "${CLI[@]}" mars-rx --iq-file "$CAP" --capture-format rtl_u8 2>/dev/null || true; } \
    | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{try{const j=JSON.parse(s);const m=/seq=(\d+)/.exec(j.recoveredAscii||"");process.stdout.write(j.ok&&m?m[1]:"")}catch{process.stdout.write("")}})' 2>/dev/null || true)"
  printf '%s' "$out"
}

# --- REGENERATION LOOP: the value persists only because each hop re-emits it ---
# GHOST_BLACKOUT_AT=N: controlled interrupt-the-air falsifier. At hop N the
# transmitter is cut (no operator needed); from then on the air carries nothing,
# so the value must DECAY — it has no durable home to fall back on. If it could
# "resume at N+1" it would mean the state lived somewhere off the air; it cannot.
misses=0
for hop in $(seq 1 "$HOPS"); do
  if [[ -n "${GHOST_BLACKOUT_AT:-}" && "$hop" -ge "$GHOST_BLACKOUT_AT" && -n "$TXPID" ]]; then
    kill "$TXPID" 2>/dev/null || true; wait "$TXPID" 2>/dev/null || true; TXPID=""
    last_before="$seq"
    echo "${RED}[ghost] hop ${hop}: ✂ AIR CUT — transmitter stopped. seq was ${last_before}; nothing is radiating now.${NC}"
  fi
  got="$(decode_seq)"
  if [[ -z "$got" ]]; then
    misses=$((misses+1))
    echo "${YELLOW}[ghost] hop ${hop}: AIR MISS (no fresh frame decoded) — state not regenerated this hop${NC}"
    if [[ "$misses" -ge 2 ]]; then
      echo "${RED}[ghost] circulation broken: 2 consecutive air misses → the value has DECAYED."
      echo "        It was held nowhere durable; it is gone. (This is the interrupt-the-air falsifier.)${NC}"
      break
    fi
    continue
  fi
  misses=0
  if [[ "$got" != "$seq" ]]; then
    echo "${YELLOW}[ghost] hop ${hop}: decoded seq=${got} (expected ${seq}) — stale/near-field; treating as live${NC}"
  fi
  seq=$((got + 1))                       # increment in the transient regen buffer
  radiate "GHOST/1 seq=${seq}"           # re-emit: the ONLY thing keeping it alive
  echo "${GREEN}[ghost] hop ${hop}: decoded ${got} → re-emitted seq=${seq}  (sustained by circulation)${NC}"
done

log "final seq=${seq} after ${HOPS} hops. Kill this process → the counter ceases to exist (no disk copy)."
log "FALSIFIER: block the antenna for > ${HOP_CAPTURE_S}s and the counter stops climbing — air is the persistence gate."
